"""
Pytest test suite for DiagnosticReport / Observation linking requirements.

Requirement:
    A clinician shall issue a DiagnosticReport referencing Observations;
    missing Observation links shall be rejected.
    Boundary cases on timestamps and numeric elements must be tested.

Conventions used throughout:
    - Resources are plain dicts that mimic a minimal FHIR R4 structure.
    - validate_diagnostic_report(report, observation_store) raises
      ValueError with a descriptive message on any violation and returns
      True on success.
    - The production module is assumed to be importable as
      `diagnostic_report_validator`.
"""

import math
from datetime import datetime, timezone, timedelta
from unittest.mock import patch, MagicMock

import pytest

# ---------------------------------------------------------------------------
# Production code under test (inline stub so the suite is self-contained).
# Replace the block below with a real import once the module exists:
#
#   from diagnostic_report_validator import validate_diagnostic_report
# ---------------------------------------------------------------------------

def validate_diagnostic_report(report: dict, observation_store: dict) -> bool:
    """
    Minimal reference implementation that the real module must satisfy.

    Parameters
    ----------
    report : dict
        FHIR-like DiagnosticReport resource.
    observation_store : dict
        Mapping of observation_id -> Observation resource dict.

    Returns
    -------
    bool
        True when the report is valid.

    Raises
    ------
    ValueError
        When any validation rule is violated.
    """
    # ── 1. Report must exist ────────────────────────────────────────────────
    if not report:
        raise ValueError("DiagnosticReport must not be empty.")

    # ── 2. resourceType ─────────────────────────────────────────────────────
    if report.get("resourceType") != "DiagnosticReport":
        raise ValueError("resourceType must be 'DiagnosticReport'.")

    # ── 3. status ───────────────────────────────────────────────────────────
    valid_statuses = {"registered", "partial", "preliminary", "final",
                      "amended", "corrected", "appended", "cancelled",
                      "entered-in-error", "unknown"}
    status = report.get("status")
    if not status:
        raise ValueError("DiagnosticReport.status is required.")
    if status not in valid_statuses:
        raise ValueError(f"Invalid status '{status}'.")

    # ── 4. subject ──────────────────────────────────────────────────────────
    if not report.get("subject", {}).get("reference"):
        raise ValueError("DiagnosticReport.subject.reference is required.")

    # ── 5. result (Observation references) ──────────────────────────────────
    results = report.get("result")
    if results is None:
        raise ValueError(
            "DiagnosticReport.result is required; at least one Observation "
            "reference must be present."
        )
    if not isinstance(results, list) or len(results) == 0:
        raise ValueError(
            "DiagnosticReport.result must be a non-empty list of Observation "
            "references."
        )

    for idx, ref_entry in enumerate(results):
        ref = ref_entry.get("reference", "")
        if not ref:
            raise ValueError(
                f"result[{idx}] is missing a 'reference' field."
            )
        # Extract ID from "Observation/<id>" pattern
        parts = ref.split("/")
        if len(parts) != 2 or parts[0] != "Observation":
            raise ValueError(
                f"result[{idx}].reference '{ref}' must follow the pattern "
                "'Observation/<id>'."
            )
        obs_id = parts[1]
        if obs_id not in observation_store:
            raise ValueError(
                f"result[{idx}].reference '{ref}' does not resolve to a "
                "known Observation."
            )

    # ── 6. effectiveDateTime / effectivePeriod ───────────────────────────────
    effective_dt = report.get("effectiveDateTime")
    effective_period = report.get("effectivePeriod")

    if effective_dt is not None:
        # Must be a valid ISO-8601 string; must not be in the future
        try:
            parsed = datetime.fromisoformat(effective_dt)
        except ValueError:
            raise ValueError(
                f"effectiveDateTime '{effective_dt}' is not a valid "
                "ISO-8601 datetime."
            )
        now = datetime.now(tz=parsed.tzinfo if parsed.tzinfo else None)
        if parsed > now:
            raise ValueError(
                "effectiveDateTime must not be in the future."
            )

    if effective_period is not None:
        start_str = effective_period.get("start")
        end_str = effective_period.get("end")
        if not start_str:
            raise ValueError("effectivePeriod.start is required.")
        try:
            start_dt = datetime.fromisoformat(start_str)
        except ValueError:
            raise ValueError(
                f"effectivePeriod.start '{start_str}' is not a valid "
                "ISO-8601 datetime."
            )
        if end_str:
            try:
                end_dt = datetime.fromisoformat(end_str)
            except ValueError:
                raise ValueError(
                    f"effectivePeriod.end '{end_str}' is not a valid "
                    "ISO-8601 datetime."
                )
            if end_dt < start_dt:
                raise ValueError(
                    "effectivePeriod.end must not be before effectivePeriod.start."
                )

    # ── 7. Observations: validate numeric valueQuantity boundaries ──────────
    for idx, ref_entry in enumerate(results):
        obs_id = ref_entry["reference"].split("/")[1]
        obs = observation_store[obs_id]

        vq = obs.get("valueQuantity")
        if vq is not None:
            value = vq.get("value")
            if value is None:
                raise ValueError(
                    f"Observation '{obs_id}' valueQuantity.value is required."
                )
            if not isinstance(value, (int, float)):
                raise ValueError(
                    f"Observation '{obs_id}' valueQuantity.value must be numeric."
                )
            if math.isnan(value) or math.isinf(value):
                raise ValueError(
                    f"Observation '{obs_id}' valueQuantity.value must be a "
                    "finite number."
                )

            low = vq.get("low")
            high = vq.get("high")
            if low is not None and value < low:
                raise ValueError(
                    f"Observation '{obs_id}' valueQuantity.value {value} is "
                    f"below the minimum {low}."
                )
            if high is not None and value > high:
                raise ValueError(
                    f"Observation '{obs_id}' valueQuantity.value {value} "
                    f"exceeds the maximum {high}."
                )

    return True


