class TestHappyPath:
    def test_valid_report_returns_true(self, valid_report, observation_store):
        assert validate_diagnostic_report(valid_report, observation_store) is True

    def test_valid_report_single_observation(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-002"},
            "result": [{"reference": "Observation/obs-001"}],
        }
        assert validate_diagnostic_report(report, observation_store) is True

    def test_all_valid_status_values(self, observation_store):
        valid_statuses = [
            "registered", "partial", "preliminary", "final",
            "amended", "corrected", "appended", "cancelled",
            "entered-in-error", "unknown",
        ]
        for status in valid_statuses:
            report = {
                "resourceType": "DiagnosticReport",
                "status": status,
                "subject": {"reference": "Patient/pat-001"},
                "result": [{"reference": "Observation/obs-001"}],
            }
            assert validate_diagnostic_report(report, observation_store) is True, (
                f"Status '{status}' should be valid"
            )

    def test_observation_without_value_quantity_is_accepted(self, observation_store):
        """Observations that carry no valueQuantity pass numeric validation."""
        observation_store["obs-text"] = {
            "resourceType": "Observation",
            "id": "obs-text",
            "status": "final",
            "code": {"text": "Clinical note"},
            "valueString": "Patient reports mild discomfort.",
        }
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-text"}],
        }
        assert validate_diagnostic_report(report, observation_store) is True


