class TestMissingObservationLinks:
    def test_missing_result_field_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            # 'result' key is intentionally absent
        }
        with pytest.raises(ValueError, match="result is required"):
            validate_diagnostic_report(report, observation_store)

    def test_empty_result_list_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [],
        }
        with pytest.raises(ValueError, match="non-empty list"):
            validate_diagnostic_report(report, observation_store)

    def test_result_not_a_list_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": "Observation/obs-001",   # wrong type
        }
        with pytest.raises(ValueError):
            validate_diagnostic_report(report, observation_store)

    def test_unknown_observation_reference_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-NONEXISTENT"}],
        }
        with pytest.raises(ValueError, match="does not resolve to a known Observation"):
            validate_diagnostic_report(report, observation_store)

    def test_mixed_valid_and_unknown_reference_raises(self, observation_store):
        """Even one unresolvable reference must fail the whole report."""
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [
                {"reference": "Observation/obs-001"},   # valid
                {"reference": "Observation/obs-GHOST"}, # invalid
            ],
        }
        with pytest.raises(ValueError, match="does not resolve"):
            validate_diagnostic_report(report, observation_store)

    def test_reference_missing_reference_field_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{}],   # dict with no 'reference' key
        }
        with pytest.raises(ValueError, match="missing a 'reference' field"):
            validate_diagnostic_report(report, observation_store)

    def test_reference_wrong_resource_type_raises(self, observation_store):
        """Reference pointing to a non-Observation resource type is rejected."""
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Condition/cond-001"}],
        }
        with pytest.raises(ValueError, match="Observation/<id>"):
            validate_diagnostic_report(report, observation_store)

    def test_reference_with_no_slash_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "obs-001"}],   # missing "Observation/" prefix
        }
        with pytest.raises(ValueError, match="Observation/<id>"):
            validate_diagnostic_report(report, observation_store)

    def test_all_results_unresolvable_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [
                {"reference": "Observation/x"},
                {"reference": "Observation/y"},
            ],
        }
        with pytest.raises(ValueError, match="does not resolve"):
            validate_diagnostic_report(report, observation_store)


