class TestMandatoryFields:
    def test_empty_report_raises(self, observation_store):
        with pytest.raises(ValueError, match="must not be empty"):
            validate_diagnostic_report({}, observation_store)

    def test_none_report_raises(self, observation_store):
        with pytest.raises((ValueError, AttributeError)):
            validate_diagnostic_report(None, observation_store)

    def test_wrong_resource_type_raises(self, observation_store):
        report = {
            "resourceType": "Observation",   # wrong
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-001"}],
        }
        with pytest.raises(ValueError, match="resourceType must be 'DiagnosticReport'"):
            validate_diagnostic_report(report, observation_store)

    def test_missing_status_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-001"}],
        }
        with pytest.raises(ValueError, match="status is required"):
            validate_diagnostic_report(report, observation_store)

    def test_invalid_status_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "PUBLISHED",   # not in FHIR value set
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-001"}],
        }
        with pytest.raises(ValueError, match="Invalid status"):
            validate_diagnostic_report(report, observation_store)

    def test_missing_subject_raises(self, observation_store):
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "result": [{"reference": "Observation/obs-001"}],
        }
        with pytest.raises(ValueError, match="subject.reference is required"):
