class TestEffectiveDateTimeBoundary:
    """effectiveDateTime must be a valid ISO-8601 date and not in the future."""

    def test_valid_datetime_accepted(self, valid_report, observation_store):
        valid_report["effectiveDateTime"] = "2023-03-01T12:00:00"
        assert validate_diagnostic_report(valid_report, observation_store) is True

    def test_datetime_with_timezone_accepted(self, valid_report, observation_store):
        valid_report["effectiveDateTime"] = "2022-11-15T08:45:00+05:30"
        assert validate_diagnostic_report(valid_report, observation_store) is True

    def test_datetime_at_midnight_accepted(self, valid_report, observation_store):
        valid_report["effectiveDateTime"] = "2022-01-01T00:00:00"
        assert validate_diagnostic_report(valid_report, observation_store) is True

    def test_datetime_one_second_in_past_accepted(self, observation_store):
        past = (datetime.now() - timedelta(seconds=1)).isoformat()
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "effectiveDateTime": past,
            "result": [{"reference": "Observation/obs-001"}],
        }
        assert validate_diagnostic_report(report, observation_store) is True

    def test_datetime_in_future_raises(self, valid_report, observation_store):
        future = (datetime.now() + timedelta(days=1)).isoformat()
        valid_report["effectiveDateTime"] = future
        with pytest.raises(ValueError, match="must not be in the future"):
            validate_diagnostic_report(valid_report, observation_store)

    def test_datetime_far_in_future_raises(self, valid_report, observation_store):
        valid_report["effectiveDateTime"] = "2099-12-31T23:59:59"
        with pytest.raises(ValueError, match="must not be in the future"):
            validate_diagnostic_report(valid_report, observation_store)

    def test_invalid_datetime_string_raises(self, valid_report, observation_store):
        valid_report["effectiveDateTime"] = "not-a-date"
        with pytest.raises(ValueError, match="not a valid ISO-8601"):
            validate_diagnostic_report(valid_report, observation_store)

    def test_datetime_date_only_raises(self, valid_report, observation_store):
        """Date-only strings are not valid ISO-8601 *datetimes*."""
        valid_report["effectiveDateTime"] = "2024-01-10"
        with pytest.raises(ValueError):
            validate_diagnostic_report(valid_report, observation_store)

    def test_datetime_none_is_allowed(self, observation_store):
        """effectiveDateTime is optional; omitting it is fine."""
        report = {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-001"}],
        }
        assert validate_diagnostic_report(report, observation_store) is True


