class TestEffectivePeriodBoundary:
    def _base_report(self):
        return {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": "Observation/obs-001"}],
        }

    def test_valid_period_accepted(self, observation_store):
        report = self._base_report()
        report["effectivePeriod"] = {
            "start": "2024-01-01T00:00:00",
            "end":   "2024-01-10T00:00:00",
        }
        assert validate_diagnostic_report(report, observation_store) is True

    def test_period_start_equals_end_accepted(self, observation_store):
        """Zero-duration period is technically valid."""
        report = self._base_report()
        report["effectivePeriod"] = {
            "start": "2024-06-01T08:00:00",
            "end":   "2024-06-01T08:00:00",
        }
        assert validate_diagnostic_report(report, observation_store) is True

    def test_period_without_end_accepted(self, observation_store):
        """Open-ended periods (no end) are allowed."""
        report = self._base_report()
        report["effectivePeriod"] = {"start": "2024-01-01T00:00:00"}
        assert validate_diagnostic_report(report, observation_store) is True

    def test_period_end_before_start_raises(self, observation_store):
        report = self._base_report()
        report["effectivePeriod"] = {
            "start": "2024-06-10T00:00:00",
            "end":   "2024-06-01T00:00:00",   # end precedes start
        }
        with pytest.raises(ValueError, match="must not be before"):
            validate_diagnostic_report(report, observation_store)

    def test_period_missing_start_raises(self, observation_store):
        report = self._base_report()
        report["effectivePeriod"] = {"end": "2024-06-01T00:00:00"}
        with pytest.raises(ValueError, match="start is required"):
            validate_diagnostic_report(report, observation_store)

    def test_period_invalid_start_raises(self, observation_store):
        report = self._base_report()
        report["effectivePeriod"] = {"start": "BAD", "end": "2024-06-01T00:00:00"}
        with pytest.raises(ValueError, match="not a valid ISO-8601"):
            validate_diagnostic_report(report, observation_store)

    def test_period_invalid_end_raises(self, observation_store):
        report = self._base_report()
        report["effectivePeriod"] = {"start": "2024-01-01T00:00:00", "end": "NOPE"}
        with pytest.raises(ValueError, match="not a valid ISO-8601"):
            validate_diagnostic_report(report, observation_store)

    def test_period_spanning_year_boundary_accepted(self, observation_store):
        report = self._base_report()
        report["effectivePeriod"] = {
            "start": "2023-12-31T23:59:59",
            "end":   "2024-01-01T00:00:01",
        }
        assert validate_diagnostic_report(report, observation_store) is True


