class TestNumericBoundary:
    def _make_obs(self, obs_id, value, low=None, high=None):
        vq = {"value": value, "unit": "unit"}
        if low is not None:
            vq["low"] = low
        if high is not None:
            vq["high"] = high
        return {
            "resourceType": "Observation",
            "id": obs_id,
            "status": "final",
            "code": {"text": "test"},
            "valueQuantity": vq,
        }

    def _make_report(self, obs_id):
        return {
            "resourceType": "DiagnosticReport",
            "status": "final",
            "subject": {"reference": "Patient/pat-001"},
            "result": [{"reference": f"Observation/{obs_id}"}],
        }

    # ── exact boundary values ───────────────────────────────────────────────

    def test_value_at_lower_bound_accepted(self):
        store = {"obs-lb": self._make_obs("obs-lb", value=40.0, low=40.0, high=200.0)}
        assert validate_diagnostic_report(self._make_report("obs-lb"), store) is True

    def test_value_at_upper_bound_accepted(self):
        store = {"obs-ub": self._make_obs("obs-ub", value=200.0, low=40.0, high=200.0)}
        assert validate_diagnostic_report(self._make_report("obs-ub"), store) is True

    def test_value_one_below_lower_bound_raises(self):
        store = {"obs-x": self._make_obs("obs-x", value=39.9, low=40.0, high=200.0)}
        with pytest.raises(ValueError, match="below the minimum"):
            validate_diagnostic_report(self._make_report("obs-x"), store)

    def test_value_one_above_upper_bound_raises(self):
        store = {"obs-x": self._make_obs("obs-x", value=200.1, low=40.0, high=200.0)}
        with pytest.raises(ValueError, match="exceeds the maximum"):
            validate_diagnostic_report(self._make_report("obs-x"), store)

    # ── special numeric values ──────────────────────────────────────────────

    def test_value_nan_raises(self):
        store = {"obs-nan": self._make_obs("obs-nan", value=float("nan"))}
        with pytest.raises(ValueError, match="finite number"):
            validate_diagnostic_report(self._make_report("obs-nan"), store)

    def test_value_positive_infinity_raises(self):
        store = {"obs-inf": self._make_obs("obs-inf", value=float("inf"))}
        with pytest.raises(ValueError, match="finite number"):
            validate_diagnostic_report(self._make_report("obs-inf"), store)

    def test_value_negative_infinity_raises(self):
        store = {"obs-ninf": self._make_obs("obs-ninf", value=float("-inf"))}
        with pytest.raises(ValueError, match="finite number"):
            validate_diagnostic_report(self._make_report("obs-ninf"), store)

    def test_value_zero_accepted_when_in_range(self):
        store = {"obs-z": self._make_obs("obs-z", value=0.0, low=-10.0, high=10.0)}
        assert validate_diagnostic_report(self._make_report("obs-z"), store) is True

    def test_value_negative_accepted_when_in_range(self):
        store = {"obs-neg": self._make_obs("obs-neg", value=-5.0, low=-10.0, high=0.0)}
        assert validate_diagnostic_report(self._make_report("obs-neg"), store) is True

    def test_value_string_instead_of_number_raises(self):
        obs = self._make_obs("obs-s", value=72.0)
        obs["valueQuantity"]["value"] = "seventy-two"
        store = {"obs-s": obs}
        with pytest.raises(ValueError, match="must be numeric"):
            validate_diagnostic_report(self._make_report("obs-s"), store)

    def test_value_none_raises(self):
        obs = self._make_obs("obs-none", value=72.0)
        obs["valueQuantity"]["value"] = None
        store = {"obs-none": obs}
        with pytest.raises(ValueError, match="value is required"):
            validate_diagnostic_report(self._make_report("obs-none"), store)

    def test_integer_value_accepted(self):
        store = {"obs-int": self._make_obs("obs-int", value=72, low=40, high=200)}
        assert validate_diagnostic_report(self._make_report("obs-int"), store) is True

    def test_very_large_valid_value(self):
